var hx = require("hbuilderx");
 
 function sleep(ms: number) {
     return new Promise(resolve => setTimeout(resolve, ms));
 }
 
 
async function installPlugin(session: any) {
    const consoleClientId = session?.cliconsole?.clientId;
    const pluginName = session?.args?.name;
    const force = session?.args?.force;
    
    if(!force){
        const pluginStatus = await hx.extensions.existsPlugin(pluginName);
        if (pluginStatus?.exists) {
            await hx.cliconsole.log({
                clientId: consoleClientId,
                msg: `插件 ${pluginName} 已存在`,
                status: "info"
            });
            return;
        }
    }
    
    await hx.extensions.installExtension(pluginName,force);

    const installedStatus = await hx.extensions.existsPlugin(pluginName);
    if (installedStatus?.exists) {
        await hx.cliconsole.log({
            clientId: consoleClientId,
            msg: `插件 ${pluginName} 安装成功`,
            status: "info"
        });
    } else {
        await hx.cliconsole.log({
            clientId: consoleClientId,
            msg: `插件 ${pluginName} 安装失败`,
            status: "info"
        });
    }
    await sleep(50);
    return;
}

export function activate(context: any) {
    context.subscriptions.push(
        hx.commands.registerCliCommand("installPlugin", installPlugin)
    );
}

export function deactivate() { }
